@dataclass
class TaskMessage:
    """Represents a task message with validation."""
    task_id: str
    task_type: str
    payload: dict
    created_at: str
    priority: int = 0
    retry_count: int = 0

    def validate(self) -> bool:
        """Validate the task message fields."""
        if not self.task_id or not isinstance(self.task_id, str):
            raise ValueError("Invalid task_id")
        if self.task_type not in ALLOWED_TASK_TYPES:
            raise ValueError(f"Invalid task_type: {self.task_type}. Allowed: {ALLOWED_TASK_TYPES}")
        if not isinstance(self.payload, dict):
            raise ValueError("Payload must be a dictionary")
        if not 0 <= self.priority <= 10:
            raise ValueError("Priority must be between 0 and 10")
        if self.retry_count < 0:
            raise ValueError("retry_count cannot be negative")
        return True

    def to_json(self) -> str:
        """Serialize to JSON string."""
        data = asdict(self)
        json_str = json.dumps(data)
        if len(json_str.encode('utf-8')) > MAX_MESSAGE_SIZE:
            raise ValueError(f"Message size exceeds maximum allowed size of {MAX_MESSAGE_SIZE} bytes")
        return json_str

    @classmethod
    def from_json(cls, json_str: str) -> 'TaskMessage':
        """Deserialize from JSON string with validation."""
        if len(json_str.encode('utf-8')) > MAX_MESSAGE_SIZE:
            raise ValueError(f"Message size exceeds maximum allowed size of {MAX_MESSAGE_SIZE} bytes")
        try:
            data = json.loads(json_str)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON: {e}")

        # Only allow known fields
        allowed_fields = {'task_id', 'task_type', 'payload', 'created_at', 'priority', 'retry_count'}
        unknown_fields = set(data.keys()) - allowed_fields
        if unknown_fields:
            raise ValueError(f"Unknown fields in message: {unknown_fields}")

        required_fields = {'task_id', 'task_type', 'payload', 'created_at'}
        missing_fields = required_fields - set(data.keys())
        if missing_fields:
            raise ValueError(f"Missing required fields: {missing_fields}")

        task = cls(**data)
        task.validate()
        return task


class RabbitMQConnection:
    """Manages RabbitMQ connection with security and retry logic."""

    def __init__(
        self,
        host: str = 'localhost',
        port: int = 5672,
        username: str = 'guest',
        password: str = 'guest',
        virtual_host: str = '/',
        use_ssl: bool = False,
        heartbeat: int = 600,
        blocked_connection_timeout: int = 300
    ):
        self._host = host
        self._port = port
        self._virtual_host = virtual_host
        self._use_ssl = use_ssl
        self._heartbeat = heartbeat
        self._blocked_connection_timeout = blocked_connection_timeout
        self._connection: Optional[pika.BlockingConnection] = None
        self._channel: Optional[pika.channel.Channel] = None

        # Use credentials securely
        self._credentials = pika.PlainCredentials(
            username=username,
            password=password
        )

    def _get_connection_parameters(self) -> pika.ConnectionParameters:
        """Build connection parameters with security settings."""
        params = pika.ConnectionParameters(
            host=self._host,
            port=self._port,
            virtual_host=self._virtual_host,
            credentials=self._credentials,
            heartbeat=self._heartbeat,
            blocked_connection_timeout=self._blocked_connection_timeout,
            connection_attempts=MAX_RETRIES,
            retry_delay=RETRY_DELAY,
        )

        if self._use_ssl:
            ssl_context = ssl.create_default_context()
            ssl_context.check_hostname = True
            ssl_context.verify_mode = ssl.CERT_REQUIRED
            params.ssl_options = pika.SSLOptions(ssl_context, self._host)

        return params

    def connect(self) -> pika.channel.Channel:
        """Establish connection with retry logic."""
        for attempt in range(1, MAX_RETRIES + 1):
            try:
                logger.info(f"Attempting to connect to RabbitMQ (attempt {attempt}/{MAX_RETRIES})")
                params = self._get_connection_parameters()
                self._connection = pika.BlockingConnection(params)
                self._channel = self._connection.channel()
                logger.info("Successfully connected to RabbitMQ")
                return self._channel
            except pika.exceptions.AMQPConnectionError as e:
                logger.warning(f"Connection attempt {attempt} failed: {e}")
                if attempt < MAX_RETRIES:
                    time.sleep(RETRY_DELAY)
                else:
                    logger.error("All connection attempts failed")
                    raise

    def close(self):
        """Safely close the connection."""
        try:
            if self._channel and self._channel.is_open:
                self._channel.close()
            if self._connection and self._connection.is_open:
                self._connection.close()
            logger.info("RabbitMQ connection closed")
        except Exception as e:
            logger.error(f"Error closing connection: {e}")

    @property
    def channel(self) -> Optional[pika.channel.Channel]:
        return self._channel

    @property
    def is_connected(self) -> bool:
        return (
            self._connection is not None
            and self._connection.is_open
            and self._channel is not None
            and self._channel.is_open
        )


class TaskPublisher:
    """Publishes task messages to RabbitMQ with reliability guarantees."""

    QUEUE_NAME = 'task_queue'
    EXCHANGE_NAME = 'task_exchange'
    ROUTING_KEY = 'task.process'
    DEAD_LETTER_EXCHANGE = 'task_dlx'
    DEAD_LETTER_QUEUE = 'task_dead_letter_queue'

    def __init__(self, connection: RabbitMQConnection):
        self._connection = connection
        self._channel: Optional[pika.channel.Channel] = None

    def setup(self):
        """Set up exchanges, queues, and bindings."""
        self._channel = self._connection.connect()

        # Enable publisher confirms for reliable publishing
        self._channel.confirm_delivery()

        # Declare dead letter exchange and queue
        self._channel.exchange_declare(
            exchange=self.DEAD_LETTER_EXCHANGE,
            exchange_type='direct',
            durable=True
        )
        self._channel.queue_declare(
            queue=self.DEAD_LETTER_QUEUE,
            durable=True
        )
        self._channel.queue_bind(
            queue=self.DEAD_LETTER_QUEUE,
            exchange=self.DEAD_LETTER_EXCHANGE,
            routing_key=self.ROUTING_KEY
        )

        # Declare main exchange
        self._channel.exchange_declare(
            exchange=self.EXCHANGE_NAME,
            exchange_type='direct',
            durable=True
        )

        # Declare main queue with dead letter configuration
        self._channel.queue_declare(
            queue=self.QUEUE_NAME,
            durable=True,
            arguments={
                'x-dead-letter-exchange': self.DEAD_LETTER_EXCHANGE,
                'x-dead-letter-routing-key': self.ROUTING_KEY,
                'x-message-ttl': 86400000,  # 24 hours TTL
                'x-max-length': 100000,  # Max queue length
            }
        )

        # Bind queue to exchange
        self._channel.queue_bind(
            queue=self.QUEUE_NAME,
            exchange=self.EXCHANGE_NAME,
            routing_key=self.ROUTING_KEY
        )

        logger.info("Publisher setup complete")

    def publish_task(self, task_type: str, payload: dict, priority: int = 0) -> str:
        """Publish a task message to the queue."""
        if not self._connection.is_connected:
            raise RuntimeError("Not connected to RabbitMQ")

        task_id = str(uuid.uuid4())
        task = TaskMessage(
            task_id=task_id,
            task_type=task_type,
            payload=payload,
            created_at=datetime.utcnow().isoformat(),
            priority=priority
        )

        # Validate before publishing
        task.validate()
        message_body = task.to_json()

        properties = pika.BasicProperties(
            delivery_mode=2,  # Persistent message
            content_type='application/json',
            content_encoding='utf-8',
            message_id=task_id,
            timestamp=int(time.time()),
            priority=priority,
            headers={
                'task_type': task_type,
                'retry_count': 0
            }
        )

        try:
            self._channel.basic_publish(
                exchange=self.EXCHANGE_NAME,
                routing_key=self.ROUTING_KEY,
                body=message_body.encode('utf-8'),
                properties=properties,
                mandatory=True  # Ensure message is routed to a queue
            )
            logger.info(f"Published task {task_id} of type '{task_type}'")
            return task_id
        except pika.exceptions.UnroutableError:
            logger.error(f"Message {task_id} was unroutable")
            raise
        except pika.exceptions.NackError:
            logger.error(f"Message {task_id} was nacked by broker")
            raise

    def close(self):
        """Close the publisher connection."""
        self._connection.close()


class TaskConsumer:
    """Consumes and processes task messages from RabbitMQ."""

    QUEUE_NAME = 'task_queue'
    MAX_TASK_RETRIES = 3

    def __init__(
        self,
        connection: RabbitMQConnection,
        prefetch_count: int = 1
    ):
        self._connection = connection
        self._prefetch_count = prefetch_count
        self._channel: Optional[pika.channel.Channel] = None
        self._task_handlers: dict[str, Callable] = {}
        self._is_consuming = False

    def register_handler(self, task_type: str, handler: Callable):
        """Register a handler function for a specific task type."""
        if task_type not in ALLOWED_TASK_TYPES:
            raise ValueError(f"Invalid task_type: {task_type}")
        if not callable(handler):
            raise ValueError("Handler must be callable")
        self._task_handlers[task_type] = handler
        logger.info(f"Registered handler for task type: {task_type}")

    def setup(self):
        """Set up the consumer."""
        self._channel = self._connection.connect()

        # Set QoS - process one message at a time
        self._channel.basic_qos(prefetch_count=self._prefetch_count)

        # Ensure queue exists (idempotent)
        self._channel.queue_declare(
            queue=self.QUEUE_NAME,
            durable=True,
            arguments={
                'x-dead-letter-exchange': 'task_dlx',
                'x-dead-letter-routing-key': 'task.process',
                'x-message-ttl': 86400000,
                'x-max-length': 100000,
            }
        )

        logger.info("Consumer setup complete")

    def _on_message(self, channel, method, properties, body):
        """Callback for processing received messages."""
        task_id = properties.message_id or 'unknown'
        logger.info(f"Received message {task_id}")

        try:
            # Deserialize and validate the message
            message_str = body.decode('utf-8')
            task = TaskMessage.from_json(message_str)

            # Find the appropriate handler
            handler = self._task_handlers.get(task.task_type)
            if handler is None:
                logger.error(f"No handler registered for task type: {task.task_type}")
                # Reject without requeue - will go to dead letter queue
                channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)
                return

            # Process the task
            logger.info(f"Processing task {task.task_id} of type '{task.task_type}'")
            handler(task)

            # Acknowledge successful processing
            channel.basic_ack(delivery_tag=method.delivery_tag)
            logger.info(f"Task {task.task_id} processed successfully")

        except ValueError as e:
            logger.error(f"Invalid message format for {task_id}: {e}")
            # Reject malformed messages without requeue
            channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)

        except Exception as e:
            logger.error(f"Error processing task {task_id}: {e}")
            # Check retry count from headers
            retry_count = 0
            if properties.headers and 'retry_count' in properties.headers:
                retry_count = properties.headers['retry_count']

            if retry_count < self.MAX_TASK_RETRIES:
                logger.info(f"Requeuing task {task_id} (retry {retry_count + 1}/{self.MAX_TASK_RETRIES})")
                # Reject and requeue for retry
                channel.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
            else:
                logger.error(f"Task {task_id} exceeded max retries, sending to dead letter queue")
                channel.basic_nack(delivery_tag=method.delivery_tag, requeue=False)

    def start_consuming(self):
        """Start consuming messages from the queue."""
        if not self._connection.is_connected:
            raise RuntimeError("Not connected to RabbitMQ")

        self._channel.basic_consume(
            queue=self.QUEUE_NAME,
            on_message_callback=self._on_message,
            auto_ack=False  # Manual acknowledgment for reliability
        )

        self._is_consuming = True
        logger.info(f"Consumer started. Waiting for messages on '{self.QUEUE_NAME}'...")

        try:
            self._channel.start_consuming()
        except KeyboardInterrupt:
            logger.info("Consumer interrupted by user")
            self.stop_consuming()

    def stop_consuming(self):
        """Gracefully stop consuming."""
        if self._is_consuming and self._channel:
            self._channel.stop_consuming()
            self._is_consuming = False
            logger.info("Consumer stopped")

    def close(self):
        """Close the consumer connection."""
        self.stop_consuming()
        self._connection.close()


