def run_publisher():
    """Run the publisher to send sample tasks."""
    conn = RabbitMQConnection(
        host='localhost',
        port=5672,
        username='guest',
        password='guest'
    )

    publisher = TaskPublisher(conn)
    try:
        publisher.setup()

        # Publish sample tasks
        tasks = [
            ('data_processing', {'dataset': 'sales_2024', 'format': 'csv'}, 5),
            ('report_generation', {'report_type': 'monthly', 'month': 'January'}, 3),
            ('email_notification', {'recipient': 'user@example.com', 'template': 'welcome'}, 1),
            ('file_conversion', {'source': 'document.docx', 'target_format': 'pdf'}, 2),
            ('cleanup', {'target': 'temp_files', 'older_than_days': 30}, 0),
        ]

        for task_type, payload, priority in tasks:
            task_id = publisher.publish_task(task_type, payload, priority)
            logger.info(f"Published task: {task_id}")
            time.sleep(0.5)

        logger.info("All tasks published successfully")

    except Exception as e:
        logger.error(f"Publisher error: {e}")
    finally:
        publisher.close()


def run_consumer():
    """Run the consumer to process tasks."""
    conn = RabbitMQConnection(
        host='localhost',
        port=5672,
        username='guest',
        password='guest'
    )

    consumer = TaskConsumer(conn, prefetch_count=1)
    try:
        consumer.setup()

        # Register task handlers
        consumer.register_handler('data_processing', handle_data_processing)
        consumer.register_handler('report_generation', handle_report_generation)
        consumer.register_handler('email_notification', handle_email_notification)
        consumer.register_handler('file_conversion', handle_file_conversion)
        consumer.register_handler('cleanup', handle_cleanup)

        # Start consuming (blocking)
        consumer.start_consuming()

    except Exception as e:
        logger.error(f"Consumer error: {e}")
    finally:
        consumer.close()


